import azure.functions as func
import os
from azure.storage.blob import BlobServiceClient, BlobClient, ContainerClient

app = func.FunctionApp(http_auth_level=func.AuthLevel.FUNCTION)

@app.route(route="readBlobFile")
def readBlobFile(req: func.HttpRequest) -> func.HttpResponse:
    container_name = os.environ.get('BLOB_CONTAINER_NAME')
    connection_string = os.environ.get('AZURE_STORAGE_CONNECTION_STRING')

    if not container_name or not connection_string:
        return func.HttpResponse(
            "Azure Storage connection string or container name not configured.",
            status_code=500
        )

    blob_path = req.params.get('path')

    if not blob_path:
        return func.HttpResponse(
            "Please pass a 'path' query parameter representing the blob path.",
            status_code=400
        )

    try:
        blob_service_client = BlobServiceClient.from_connection_string(connection_string)
        blob_client = blob_service_client.get_blob_client(container=container_name, blob=blob_path)

        if not blob_client.exists():
            return func.HttpResponse(
                f"Blob '{blob_path}' not found in container '{container_name}'.",
                status_code=404
            )

        # Download the blob content
        blob_data = blob_client.download_blob().readall()

        # Determine content type (simple guess, or you might have a lookup)
        # For a more robust solution, consider using mimetypes or storing content type as metadata
        if blob_path.lower().endswith(('.png', '.jpg', '.jpeg', '.gif', '.bmp', '.webp')):
            content_type = 'image/*' # Azure Functions handles specific image types based on browser
        elif blob_path.lower().endswith('.pdf'):
            content_type = 'application/pdf'
        elif blob_path.lower().endswith('.json'):
            content_type = 'application/json'
        elif blob_path.lower().endswith('.xml'):
            content_type = 'application/xml'
        elif blob_path.lower().endswith('.txt'):
            content_type = 'text/plain'
        elif blob_path.lower().endswith('.csv'):
            content_type = 'text/csv'
        else:
            content_type = 'application/octet-stream' # Default for unknown types

        return func.HttpResponse(
            body=blob_data,
            mimetype=content_type,
            status_code=200
        )

    except Exception as e:
        return func.HttpResponse(
            f"An error occurred while reading the blob: {str(e)}",
            status_code=500
        )